import{getAuth,onAuthStateChanged}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-auth.js";import{getFirestore,doc,getDoc}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";import{app}from"../firebase-config/firebase.js";const auth=getAuth(app),db=getFirestore(app);window.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("credits-used");e?(console.log("Setting up onAuthStateChanged listener..."),onAuthStateChanged(auth,t=>{t?(console.log("User is logged in:",t.uid,t.email),async function(t){if(console.log("loadRemainingCredits called with UID:",t),t&&e)try{const o=doc(db,"credits",t);console.log("Fetching credits from Firestore...");const s=await getDoc(o);let n="0 (Configure Later)";if(s.exists()){const e=s.data();console.log("Credits document data:",e);const t=e.maxCredits,o=e.usedCredits||0;n="unlimited"===t||-1===t?"Unlimited":Math.max(t-o,0)}else console.log("Credits document does not exist for user:",t);console.log("Remaining credits to display:",n),e.textContent=n,sessionStorage.setItem("creditsUsed",n)}catch(t){console.error("Error fetching credits:",t),e.textContent="0 (Error)"}else console.log("No userUID or credits element. Exiting.")}(t.uid)):(console.log("No user logged in."),e.textContent="0 (Not logged in)")})):console.warn("Element #credits-used not found!")});